import { type PropsWithChildren, useCallback, useEffect, useMemo } from 'react';

import { TooltipPortal } from './TooltipPortal.js';
import { useThrottledCallbackOnResize } from '../../../hooks/useThrottledCallbackOnResize.js';
import { useThrottledCallbackOnScroll } from '../../../hooks/useThrottledCallbackOnScroll.js';
import { throttleRaf } from '../../../utils/throttleRaf.js';
import { useOverlay } from '../contexts/OverlayContext.js';
import { useTooltip } from '../contexts/TooltipContext.js';
import { useTooltipReducer } from '../useTooltipReducer.js';

export const DynamicTooltip = (
  props: PropsWithChildren<{
    pinned: boolean;
    absoluteX: number;
    absoluteY: number;
  }>,
) => {
  const { absoluteX, absoluteY, pinned } = props;
  const overlay = useOverlay();
  const dispatch = useTooltipReducer();
  const tooltip = useTooltip();

  const onEscapeKeyPressedHandler = useCallback((event: KeyboardEvent) => {
    if (event.key === 'Escape') {
      dispatch({ type: 'RESET_TOOLTIP' })();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    window.addEventListener('keyup', onEscapeKeyPressedHandler);
    return () => {
      window.removeEventListener('keyup', onEscapeKeyPressedHandler);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useThrottledCallbackOnScroll(false, () => {
    if (!overlay.overlayRef.current) {
      return;
    }

    if (tooltip.getState().pinned) {
      dispatch({
        type: 'UPDATE_POSITION',
        payload: { type: 'non-resize', scroll: true },
      })();
      return;
    }

    dispatch({ type: 'SET_OUT_BOUNDS' })();
  });

  useThrottledCallbackOnResize(
    overlay.overlayRef,
    dispatch({ type: 'UPDATE_POSITION', payload: { type: 'resize' } }),
    !pinned,
  );

  const pointerMoveCallback = useMemo(
    () =>
      throttleRaf((event: PointerEvent) => {
        if (event.pressure && tooltip.getState().pinned) {
          if (
            !overlay.overlayRef.current ||
            overlay.overlayRef.current.contains(event.target as Node)
          ) {
            return;
          }
          dispatch({
            type: 'UPDATE_POSITION',
            payload: { type: 'non-resize' },
          })();
          return;
        }
      }),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [],
  );

  const pointerUpCallback = useMemo(
    () =>
      throttleRaf((event: PointerEvent) => {
        if (tooltip.getState().pinned) {
          if (
            !overlay.overlayRef.current ||
            overlay.overlayRef.current.contains(event.target as Node)
          ) {
            return;
          }
          dispatch({
            type: 'UPDATE_POSITION',
            payload: { type: 'non-resize' },
          })();
          return;
        }
      }),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [],
  );

  useEffect(() => {
    if (!pinned || !overlay.overlayRef.current) {
      return;
    }
    window.addEventListener('pointermove', pointerMoveCallback);
    window.addEventListener('pointerup', pointerUpCallback);

    return () => {
      window.removeEventListener('pointermove', pointerMoveCallback);
      window.removeEventListener('pointerup', pointerUpCallback);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [pinned]);

  return (
    <TooltipPortal
      isInteractive={pinned}
      absoluteX={absoluteX}
      absoluteY={absoluteY}
      onMouseLeave={dispatch({ type: 'TOOLTIP_MOUSE_LEAVE' })}
      onScrollCapture={() => dispatch({ type: 'TOOLTIP_MOUSE_LEAVE' })}
    >
      {props.children}
    </TooltipPortal>
  );
};
